import numpy as np
import cvxpy as cp

# ==============================================================================
# ⚛️ QuantumNEAT: K=2 PPT Symmetric Extension SDP
# ==============================================================================
# We load the candidate NPT state generated by our GAN and test it using a 
# Semidefinite Program (SDP). 
# We ask the solver: "Can you find a 27x27 density matrix X that is an extension 
# of our 9x9 state, is symmetric under B1/B2 swap, and is PPT across A|B1B2?"
#
# If Feasible -> It passed the k=2 filter! It is 2-undistillable.
# If Infeasible -> It failed. It is distillable with 2 copies.
# ==============================================================================

def build_swap_operator(dA, dB):
    """Builds the swap operator on A (x) B1 (x) B2 swapping B1 and B2"""
    S = np.zeros((dA * dB * dB, dA * dB * dB), dtype=np.complex128)
    for a in range(dA):
        for b1 in range(dB):
            for b2 in range(dB):
                idx1 = a * (dB * dB) + b1 * dB + b2
                idx2 = a * (dB * dB) + b2 * dB + b1
                S[idx1, idx2] = 1.0
    return S

def check_k2_symmetric_extension(rho_target, dA=3, dB=3):
    print("Loading candidate state...")
    
    # Define the SDP Variable for the extended state (27x27)
    dim_ext = dA * dB * dB
    X = cp.Variable((dim_ext, dim_ext), hermitian=True)
    
    constraints = [X >> 0] # X must be positive semidefinite
    constraints += [cp.trace(X) == 1]
    
    # 1. Symmetry constraint: X = Swap * X * Swap
    S = build_swap_operator(dA, dB)
    constraints += [X == S @ X @ S]
    
    # 2. Partial Trace constraint: Tr_B2(X) == rho_target
    # We construct the partial trace using linear constraints
    # X is indexed by (a, b1, b2). Tr_B2(X)_{a, b1, a', b1'} = sum_b2 X_{a, b1, b2, a', b1', b2}
    print("Building partial trace constraints...")
    rho_tr = cp.Variable((dA*dB, dA*dB), hermitian=True)
    
    # Build expressions for the elements of the partial trace
    for a in range(dA):
        for b1 in range(dB):
            for a_prime in range(dA):
                for b1_prime in range(dB):
                    idx_rho_1 = a * dB + b1
                    idx_rho_2 = a_prime * dB + b1_prime
                    
                    # Sum over the traced subsystem b2
                    trace_sum = 0
                    for b2 in range(dB):
                        idx_X_1 = a * (dB * dB) + b1 * dB + b2
                        idx_X_2 = a_prime * (dB * dB) + b1_prime * dB + b2
                        trace_sum += X[idx_X_1, idx_X_2]
                        
                    constraints += [trace_sum == rho_target[idx_rho_1, idx_rho_2]]

    # 3. PPT condition: Partial transpose over B1 and B2 must be positive
    # We construct the partial transposed matrix X_PT
    print("Building Partial Transpose (PPT) constraints...")
    X_PT = cp.Variable((dim_ext, dim_ext), hermitian=True)
    for a in range(dA):
        for b1 in range(dB):
            for b2 in range(dB):
                for a_prime in range(dA):
                    for b1_prime in range(dB):
                        for b2_prime in range(dB):
                            idx_1 = a * (dB * dB) + b1 * dB + b2
                            idx_2 = a_prime * (dB * dB) + b1_prime * dB + b2_prime
                            
                            # Partial transpose: swap B subsystem indices
                            idx_pt_1 = a * (dB * dB) + b1_prime * dB + b2_prime
                            idx_pt_2 = a_prime * (dB * dB) + b1 * dB + b2
                            
                            constraints += [X_PT[idx_1, idx_2] == X[idx_pt_1, idx_pt_2]]
                            
    constraints += [X_PT >> 0]

    # Solve the SDP
    print("Submitting SDP to the solver (SCS/MOSEK)...")
    prob = cp.Problem(cp.Minimize(0), constraints)
    
    try:
        prob.solve(solver=cp.SCS, verbose=False)
    except:
        prob.solve(verbose=False)
        
    print(f"\nSDP Result Status: {prob.status.upper()}")
    
    if prob.status == "optimal":
        print("🏆 FEASIBLE! The state has a k=2 PPT Symmetric Extension.")
        print("This means it is 2-undistillable. The candidate survived the second filter!")
    else:
        print("❌ INFEASIBLE. The state does NOT have a k=2 PPT Symmetric Extension.")
        print("This means the discriminator was right: the state IS distillable if we use 2 copies.")

if __name__ == "__main__":
    try:
        candidate_rho = np.load("candidate_mc.npy")
        check_k2_symmetric_extension(candidate_rho)
    except FileNotFoundError:
        print("File 'candidate_mc.npy' not found!")
